    },
    {
        name: 'Reels Pro',
        reels: 3600,
        price: '35.00',
        id: 'price_1Sn17TIA2zQnWbn5d7pa8iB8',
        features: ['~7× 2K videos (20s)', 'Priority generation speed', 'Private gallery', 'Commercial license']
    },
    {
        name: 'Reels Studio',
        reels: 9000,
        price: '85.00',
